function candidate(type) {
  const record = db[type];
  if (!record || !record.extensions || record.extensions.length === 0) return;

  extensions[type] = record.extensions;

  const rank = ["nginx", "apache", undefined, "iana"];

  for (const suffix of record.extensions) {
    const current = types[suffix];

    if (current) {
      const currentRank = rank.indexOf(db[current] && db[current].source);
      const nextRank = rank.indexOf(record.source);

      if (current !== "application/octet-stream" && (currentRank > nextRank || (currentRank === nextRank && current.slice(0, 12) === "application/"))) {
        continue;
      }
    }

    types[suffix] = type;
  }
}
